import{_ as t,o as a,c as r,a0 as n}from"./chunks/framework.jwovEGr5.js";const h=JSON.parse('{"title":"Manual Test Plan Overview","description":"","frontmatter":{},"headers":[],"relativePath":"testing/test-plan-overview.md","filePath":"testing/test-plan-overview.md"}'),o={name:"testing/test-plan-overview.md"};function i(l,e,s,d,c,p){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="manual-test-plan-overview" tabindex="-1">Manual Test Plan Overview <a class="header-anchor" href="#manual-test-plan-overview" aria-label="Permalink to &quot;Manual Test Plan Overview&quot;">​</a></h1><p>This guide is the shared setup for every manual testing guide in this section.</p><h2 id="_1-seed-data" tabindex="-1">1. Seed data <a class="header-anchor" href="#_1-seed-data" aria-label="Permalink to &quot;1. Seed data&quot;">​</a></h2><p>Prepare one stable demo dataset before any test run.</p><p>Minimum seed:</p><ol><li><strong>2 kingdoms</strong></li><li><strong>2 alliances in each kingdom</strong></li><li><strong>about 30 players total</strong></li><li><strong>1 event instance for each default event</strong></li><li><strong>1 alliance on a premium direct plan</strong></li><li><strong>1 alliance on the free tier</strong></li><li><strong>1 suspended alliance</strong></li><li><strong>1 applied import that was later deleted with results</strong></li><li><strong>1 pre-existing player that later appears again in an import</strong></li></ol><p>Helpful extras:</p><ol><li>one accepted kingdom grant</li><li>one pending grant</li><li>one import in <code>completed_with_review</code></li><li>one import in <code>restored_draft</code></li></ol><h2 id="_2-accounts-to-create" tabindex="-1">2. Accounts to create <a class="header-anchor" href="#_2-accounts-to-create" aria-label="Permalink to &quot;2. Accounts to create&quot;">​</a></h2><p>Create at least these accounts:</p><ol><li><strong>1 Supreme Admin</strong></li><li><strong>1 King</strong></li><li><strong>1 Alliance Leader</strong></li><li><strong>1 Co-Leader</strong></li><li><strong>1 Alliance Player</strong></li><li><strong>1 multi-role user</strong></li></ol><p>The multi-role user should hold at least:</p><ul><li>one kingdom-scoped role</li><li>one alliance-scoped role in a different place</li></ul><h2 id="_3-browser-setup" tabindex="-1">3. Browser setup <a class="header-anchor" href="#_3-browser-setup" aria-label="Permalink to &quot;3. Browser setup&quot;">​</a></h2><p>Run the main manual pass in a current desktop browser at normal desktop width.</p><p>Recommended minimum:</p><ol><li>one current Chromium-based browser for the full pass</li><li>one second browser family for a smoke check on key flows</li></ol><p>Use a clean profile or incognito window when role switching would otherwise reuse the wrong session.</p><h2 id="_4-reset-between-test-runs" tabindex="-1">4. Reset between test runs <a class="header-anchor" href="#_4-reset-between-test-runs" aria-label="Permalink to &quot;4. Reset between test runs&quot;">​</a></h2><p>Before repeating a test pack:</p><ol><li>return changed plans to their original state</li><li>revoke grants created only for testing</li><li>unsuspend anything suspended only for testing</li><li>clear or recreate imports used only for rollback tests</li><li>restore deleted demo data if the next run expects it</li><li>log out of every account</li></ol><p>If a run changes too much state, reseed the dataset rather than trying to patch it by hand.</p>',22)])])}const g=t(o,[["render",i]]);export{h as __pageData,g as default};
